LogicalResult
ScanOp::inferReturnTypes(MLIRContext *context, std::optional<Location> loc,
                         ScanOp::Adaptor adaptor,
                         SmallVectorImpl<Type> &inferredReturnTypes) {

  auto operands = adaptor.getOperands();
